import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API = process.env.REACT_APP_API_BASE;

export default function UploadBills({ employee }) {
  const navigate = useNavigate();
  const [files, setFiles] = useState(null);
  const [bills, setBills] = useState([]);

  // Fetch existing bills
  useEffect(() => {
    if (!employee?.empld) return;

    axios
      .get(`${API}/bills/${employee.empld}`)
      .then((res) => setBills(res.data.bills || []))
      .catch(() => setBills([]));
  }, [employee]);

  // Upload bills
  const handleUpload = async () => {
    if (!files) return alert("Please select a file");

    const formData = new FormData();
    for (let f of files) formData.append("bills", f);

    formData.append("empId", employee.empld);

    await axios.post(`${API}/bills/upload`, formData);
    window.location.reload();
  };

  // Delete bill
  const deleteBill = async (id) => {
    await axios.delete(`${API}/bills/delete/${id}`);
    setBills((prev) => prev.filter((b) => b.id !== id));
  };

  return (
    <div className="upload-bills-container">

      {/* BACK BUTTON + TITLE */}
      <div className="header-row">
        <button className="back-btn" onClick={() => navigate(-1)}>
          ←
        </button>
        <h2>Upload Bills</h2>
      </div>

      <p className="employee-info">
        Employee: {employee?.name} • {employee?.empld}
      </p>

      {/* ---------------- UPLOAD SECTION ---------------- */}
      <div className="upload-section">
        <label className="upload-label">Upload Bills</label>

        <div className="upload-box">
          <input
            type="file"
            multiple
            onChange={(e) => setFiles(e.target.files)}
          />

          <button className="upload-btn" onClick={handleUpload}>
            Upload
          </button>
        </div>
      </div>

      {/* ---------------- TABLE ---------------- */}
      <table className="bills-table">
        <thead>
          <tr>
            <th>Date</th>
            <th>File Name</th>
            <th>Preview</th>
            <th>Delete</th>
          </tr>
        </thead>

        <tbody>
          {bills.length === 0 ? (
            <tr>
              <td colSpan="4" className="no-data">
                No bills uploaded
              </td>
            </tr>
          ) : (
            bills.map((bill) => (
              <tr key={bill.id}>
                <td>{bill.uploaded_at?.split("T")[0]}</td>
                <td>{bill.file_name}</td>
                <td>
                  <a
                    href={`${API}/${bill.file_path}`}
                    target="_blank"
                    rel="noreferrer"
                  >
                    View
                  </a>
                </td>
                <td>
                  <button
                    className="delete-btn"
                    onClick={() => deleteBill(bill.id)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>

      {/* ❌ NO HISTORY TEXT  
          ❌ NO DOWNLOAD BUTTON  
          ❌ NO EXTRA SECTIONS */}
    </div>
  );
}
